from pymongo import MongoClient
from typing import Optional


def get_database_connection(
    host: str = "localhost",
    port: int = 27017,
    database: str = "mydb"
):
    """Establish a connection to MongoDB and return the database object."""
    client = MongoClient(host, port)
    return client[database]


def find_user_by_email(
    email: str,
    db=None,
    collection_name: str = "users",
    host: str = "localhost",
    port: int = 27017,
    database: str = "mydb"
) -> Optional[dict]:
    """
    Find a single user by their exact email address.

    Args:
        email: The email address to search for.
        db: An existing database connection (optional).
        collection_name: Name of the users collection.
        host: MongoDB host.
        port: MongoDB port.
        database: Database name.

    Returns:
        A dictionary representing the user document, or None if not found.
    """
    if db is None:
        db = get_database_connection(host, port, database)

    collection = db[collection_name]
    user = collection.find_one({"email": email})
    return user


def find_users_by_email_pattern(
    email_pattern: str,
    db=None,
    collection_name: str = "users",
    host: str = "localhost",
    port: int = 27017,
    database: str = "mydb"
) -> list:
    """
    Find users whose email matches a regex pattern.

    Args:
        email_pattern: A regex pattern to match email addresses
                       (e.g., ".*@example\\.com" for all example.com emails).
        db: An existing database connection (optional).
        collection_name: Name of the users collection.
        host: MongoDB host.
        port: MongoDB port.
        database: Database name.

    Returns:
        A list of user documents matching the pattern.
    """
    if db is None:
        db = get_database_connection(host, port, database)

    collection = db[collection_name]
    query = {"email": {"$regex": email_pattern, "$options": "i"}}
    users = list(collection.find(query))
    return users


def find_users_by_email_domain(
    domain: str,
    db=None,
    collection_name: str = "users",
    host: str = "localhost",
    port: int = 27017,
    database: str = "mydb"
) -> list:
    """
    Find all users with an email from a specific domain.

    Args:
        domain: The email domain to search for (e.g., "example.com").
        db: An existing database connection (optional).
        collection_name: Name of the users collection.
        host: MongoDB host.
        port: MongoDB port.
        database: Database name.

    Returns:
        A list of user documents with emails from the specified domain.
    """
    if db is None:
        db = get_database_connection(host, port, database)

    collection = db[collection_name]
    pattern = f"@{domain.replace('.', '\\.')}$"
    query = {"email": {"$regex": pattern, "$options": "i"}}
    users = list(collection.find(query))
    return users


def find_users_by_email_list(
    emails: list,
    db=None,
    collection_name: str = "users",
    host: str = "localhost",
    port: int = 27017,
    database: str = "mydb"
) -> list:
    """
    Find multiple users by a list of email addresses.

    Args:
        emails: A list of email addresses to search for.
        db: An existing database connection (optional).
        collection_name: Name of the users collection.
        host: MongoDB host.
        port: MongoDB port.
        database: Database name.

    Returns:
        A list of user documents matching any of the provided emails.
    """
    if db is None:
        db = get_database_connection(host, port, database)

    collection = db[collection_name]
    query = {"email": {"$in": emails}}
    users = list(collection.find(query))
    return users


